wire [1024:0] data;
wire [7:0] shift_val;
assign result = data << {shift_val, 3'd0};

parameter DATA_BYTE = 128;
parameter EOP_WIDTH = 8;
wire [EOP_WIDTH-2:0] sop2_byte;
wire [1024:0] data;
assign result = data << (DATA_BYTE - sop2_byte);

wire [31:0] val;
wire [7:0] amount;
assign result = val << {amount, 3'd0};
